(/* Flux-local HTMX-compatible runtime for the current Django templates. */
function () {
  'use strict';

  const processed = new WeakSet();
  const timers = new WeakMap();
  const inFlight = new WeakSet();
  let activeRequestCount = 0;

  function attr(element, name) {
    return element.getAttribute(name) || element.getAttribute('data-' + name);
  }

  function trigger(element, name, detail) {
    const event = new CustomEvent(name, { bubbles: true, cancelable: true, detail: detail || {} });
    element.dispatchEvent(event);
    return event;
  }

  function find(rootOrSelector, selector) {
    if (selector) return rootOrSelector.querySelector(selector);
    return document.querySelector(rootOrSelector);
  }

  function findAll(rootOrSelector, selector) {
    const root = selector ? rootOrSelector : document;
    const query = selector || rootOrSelector;
    return Array.prototype.slice.call(root.querySelectorAll(query));
  }

  function closest(element, selector) {
    return element.closest(selector);
  }

  function parseSeconds(value) {
    const text = String(value || '').trim();
    if (text.endsWith('ms')) return Number(text.slice(0, -2));
    if (text.endsWith('s')) return Number(text.slice(0, -1)) * 1000;
    if (text.endsWith('m')) return Number(text.slice(0, -1)) * 60000;
    return Number(text);
  }

  function splitEveryTriggerSpec(spec) {
    const text = String(spec || '').trim();
    const conditionStart = text.indexOf('[');
    if (conditionStart < 0) return { interval: text, condition: '' };
    const conditionEnd = text.lastIndexOf(']');
    return {
      interval: text.slice(0, conditionStart).trim(),
      condition: conditionEnd > conditionStart ? text.slice(conditionStart + 1, conditionEnd).trim() : ''
    };
  }

  function triggerConditionPasses(condition, element) {
    if (!condition) return true;
    if (condition === 'fluxDisplayPulseCanRun()') {
      return typeof window.fluxDisplayPulseCanRun === 'function' ? window.fluxDisplayPulseCanRun(element) : true;
    }
    return true;
  }

  function targetFor(element) {
    const target = attr(element, 'hx-target');
    if (!target) return element;
    if (target === 'this') return element;
    return document.querySelector(target);
  }

  function clearElementTimers(element) {
    const existing = timers.get(element);
    if (!existing) return;
    existing.forEach(function (timer) { window.clearInterval(timer); });
    timers.delete(element);
  }

  function cleanupTree(root, includeRoot) {
    if (!root || root.nodeType !== 1) return;
    if (includeRoot) clearElementTimers(root);
    findAll(root, '[hx-get], [data-hx-get], [hx-post], [data-hx-post]').forEach(clearElementTimers);
  }

  function beginRequest(element) {
    inFlight.add(element);
    activeRequestCount += 1;
    document.body.classList.add('htmx-request');
  }

  function endRequest(element) {
    inFlight.delete(element);
    activeRequestCount = Math.max(0, activeRequestCount - 1);
    if (activeRequestCount === 0) document.body.classList.remove('htmx-request');
  }

  function includeElementFor(element) {
    const include = attr(element, 'hx-include');
    if (include === 'closest form') return element.closest('form');
    if (include) return document.querySelector(include);
    if (element.tagName === 'FORM') return element;
    return null;
  }

  function csrfToken(formData) {
    const explicit = formData && formData.get('csrfmiddlewaretoken');
    if (explicit) return explicit;
    const cookie = document.cookie.split('; ').find(function (part) { return part.startsWith('csrftoken='); });
    return cookie ? decodeURIComponent(cookie.slice('csrftoken='.length)) : '';
  }

  function requestBody(element, method, url) {
    const include = includeElementFor(element);
    const formData = include ? new FormData(include) : new FormData();
    if (element.name && element.value && element.tagName !== 'FORM') formData.set(element.name, element.value);
    if (method === 'GET') {
      const params = new URLSearchParams(formData);
      const finalUrl = new URL(url, window.location.href);
      params.forEach(function (value, key) { finalUrl.searchParams.set(key, value); });
      return { url: finalUrl.toString(), body: null, formData: formData, multipart: false };
    }
    const multipart = include && include.enctype === 'multipart/form-data';
    return {
      url: url,
      body: multipart ? formData : new URLSearchParams(formData).toString(),
      formData: formData,
      multipart: multipart
    };
  }

  function swapResponse(element, html, responseUrl) {
    const target = targetFor(element);
    if (!target) return;
    const select = attr(element, 'hx-select');
    const swap = (attr(element, 'hx-swap') || 'innerHTML').split(' ')[0];
    const doc = new DOMParser().parseFromString(html, 'text/html');
    const selected = select ? doc.querySelector(select) : doc.body;
    if (!selected) return;
    trigger(target, 'htmx:beforeSwap', { elt: target, serverResponse: html, responsePath: responseUrl });
    let settled = target;
    if (swap === 'outerHTML') {
      cleanupTree(target, true);
      target.outerHTML = selected.outerHTML;
      settled = select ? document.querySelector(select) : null;
    } else {
      cleanupTree(target, false);
      target.innerHTML = selected.innerHTML;
    }
    const eventTarget = settled || document.body;
    process(eventTarget);
    trigger(eventTarget, 'htmx:afterSwap', { elt: eventTarget, responsePath: responseUrl });
    window.setTimeout(function () {
      trigger(eventTarget, 'htmx:afterSettle', { elt: eventTarget, responsePath: responseUrl });
      trigger(eventTarget, 'htmx:load', { elt: eventTarget });
    }, 20);
  }

  function pushHistory(element, finalUrl) {
    const push = attr(element, 'hx-push-url');
    if (!push || push === 'false') return;
    const url = push === 'true' ? finalUrl : push;
    window.history.pushState({ htmx: true }, '', url);
  }

  function request(element, method, url, event) {
    if (event) event.preventDefault();
    if (inFlight.has(element)) return;
    const config = { elt: element, path: url, verb: method.toLowerCase() };
    const configEvent = trigger(element, 'htmx:configRequest', config);
    if (configEvent.defaultPrevented) return;
    const info = requestBody(element, method, config.path);
    const headers = { 'HX-Request': 'true' };
    const token = csrfToken(info.formData);
    if (token) headers['X-CSRFToken'] = token;
    if (method !== 'GET' && !info.multipart) headers['Content-Type'] = 'application/x-www-form-urlencoded';
    beginRequest(element);
    trigger(element, 'htmx:beforeRequest', { elt: element, path: info.url, verb: method.toLowerCase() });
    fetch(info.url, {
      method: method,
      headers: headers,
      body: info.body,
      credentials: 'same-origin'
    }).then(function (response) {
      return response.text().then(function (html) { return { response: response, html: html }; });
    }).then(function (payload) {
      if (payload.response.ok) {
        swapResponse(element, payload.html, payload.response.url);
        if (method === 'GET') pushHistory(element, info.url);
      }
      trigger(element, 'htmx:afterRequest', { elt: element, successful: payload.response.ok, xhr: payload.response });
    }).catch(function (error) {
      trigger(element, 'htmx:sendError', { elt: element, error: error });
    }).finally(function () {
      endRequest(element);
    });
  }

  function eventNameFor(element) {
    if (element.tagName === 'FORM') return 'submit';
    if (element.tagName === 'SELECT') return 'change';
    if (element.tagName === 'INPUT' && element.type !== 'button' && element.type !== 'submit') return 'change';
    return 'click';
  }

  function bindTrigger(element, method, url, spec) {
    const trimmed = String(spec || '').trim();
    if (!trimmed) return;
    if (trimmed.startsWith('every ')) {
      const every = splitEveryTriggerSpec(trimmed.slice('every '.length));
      const delay = parseSeconds(every.interval);
      if (delay > 0) {
        const existing = timers.get(element) || [];
        existing.push(window.setInterval(function () {
          if (triggerConditionPasses(every.condition, element)) request(element, method, url);
        }, delay));
        timers.set(element, existing);
      }
      return;
    }
    const tokens = trimmed.split(' ').filter(Boolean);
    const name = tokens[0] === 'changed' ? 'change' : tokens[0];
    const delayToken = tokens.find(function (token) { return token.startsWith('delay:'); });
    const delay = delayToken ? parseSeconds(delayToken.slice('delay:'.length)) : 0;
    const once = tokens.indexOf('once') >= 0;
    let pending = null;
    const handler = function (event) {
      if (delay > 0) {
        window.clearTimeout(pending);
        pending = window.setTimeout(function () { request(element, method, url, event); }, delay);
      } else {
        request(element, method, url, event);
      }
    };
    if (name === 'load') {
      window.setTimeout(function () { request(element, method, url); }, delay || 0);
    } else {
      element.addEventListener(name, handler, { once: once });
    }
  }

  function processElement(element) {
    if (processed.has(element)) return;
    const getUrl = attr(element, 'hx-get');
    const postUrl = attr(element, 'hx-post');
    if (!getUrl && !postUrl) return;
    processed.add(element);
    const method = getUrl ? 'GET' : 'POST';
    const url = getUrl || postUrl;
    const triggerSpec = attr(element, 'hx-trigger');
    if (triggerSpec) {
      triggerSpec.split(',').forEach(function (spec) { bindTrigger(element, method, url, spec); });
    } else {
      bindTrigger(element, method, url, eventNameFor(element));
    }
  }

  function process(root) {
    const start = root || document.body;
    if (start.nodeType !== 1 && start !== document) return;
    if (start.matches && (attr(start, 'hx-get') || attr(start, 'hx-post'))) processElement(start);
    findAll(start, '[hx-get], [data-hx-get], [hx-post], [data-hx-post]').forEach(processElement);
  }

  function ajax(method, url, options) {
    const source = options && options.source ? options.source : document.body;
    return request(source, String(method || 'GET').toUpperCase(), url);
  }

  window.htmx = {
    version: '2.0.4-flux-local',
    process: process,
    on: function (target, event, handler) {
      if (typeof target === 'string') return document.body.addEventListener(target, event);
      return target.addEventListener(event, handler);
    },
    off: function (target, event, handler) {
      if (typeof target === 'string') return document.body.removeEventListener(target, event);
      return target.removeEventListener(event, handler);
    },
    trigger: trigger,
    find: find,
    findAll: findAll,
    closest: closest,
    ajax: ajax
  };

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function () { process(document.body); trigger(document.body, 'htmx:load', { elt: document.body }); });
  } else {
    process(document.body);
    trigger(document.body, 'htmx:load', { elt: document.body });
  }
})();
